def parse_csv(data: str) -> list:
    """Parse CSV string to list of lists."""
    import csv
    from io import StringIO

    if not isinstance(data, str):
        return []

    try:
        reader = csv.reader(StringIO(data))
        return list(reader)
    except csv.Error as e:
        return []

